# This python script generates a C finite state automaton for simple syntax highlighting
# (strings, operators, numbers and keywords)

from enum import Enum

operators = ["and","or","xor","not", "del", "EE", "in", "parallel", "is"]

keywords = ["if","while","for", "foreach", "return", "import", "local", "await", "define", "init", "function", "method", "continue", "break", "pass", "True", "False", "None", "do", "end", "then"]


# ------

accepted_chars = ["\"", "'", "+","*","-","/","<",">","=","%","&","@","!", ",", ";", "\n", "#", "$", "[", "]", "(", ")", "{", "}", "\\", "_", " ", "\t", ".", ":", "~"]

class WordAutomaton:
    def __init__(self):
        self.table = {'start': {}}
        self.finals = {}
        self.state_counter = 0
    
    def new_state(self):
        self.state_counter += 1
        return f's{self.state_counter}'

    def update(self, word_class, class_name):
        for word in word_class:
            self.update_path(word, class_name)
    
    def update_path(self, word, class_name):
        letters = list(word)
        state = 'start'
        while len(letters) > 0:
            letter = letters.pop(0)
            try:
                state = self.table[state][letter]
            except:
                new_state = self.new_state()
                self.table[state][letter] = new_state
                self.table[new_state] = {}
                state = new_state

                if len(letters) == 0:
                    assert (not (new_state in self.finals))
                    self.finals[new_state] = class_name
    
    def write_header(self, file):
        file.write("/*\n * This file is automatically generated. Don't modify it manually\n */\n")

    def generate_jump_function(self, state, file):
        file.write(f'uint8_t jump_{state}(char c) {'{'}\n')
        file.write(f'    switch (c) {'{'}\n')
        for (char, state) in self.table[state].items():
            file.write(f"        case '{char}':\n")
            file.write(f'            return WA_{state.upper()};\n')
        file.write(f'        default:\n')
        file.write(f'            return 0;\n')
        file.write('    }\n')
        file.write('}\n\n')
    
    def generate_final_states_array(self, file):
        file.write('static const uint8_t final_states[] = {\n')
        states = list(self.table.keys())
        for i in range(len(states)):
            if states[i] in self.finals:
                file.write(f'    WA_{self.finals[states[i]].upper()}')
            else:
                file.write('    0')
            if i < len(states) - 1:
                file.write(',')
            file.write('\n')
        file.write('};\n\n')
    

    def generate_states_functions_array(self, file):
        file.write('static uint8_t (*states_functions[])(char) = {\n')
        states = list(self.table.keys())
        for i in range(len(states)):
            file.write(f'    jump_{states[i]}')
            if i < len(states) - 1:
                file.write(',')
            file.write('\n')
        file.write('};\n\n')


    def generate_is_final_function(self, file):
        file.write(f'uint8_t wa_get_final(uint8_t state) {'{'}\n')
        file.write(f'    return final_states[state];\n')
        file.write('}\n\n')
    
    def generate_next_state_function(self, file):
        file.write('uint8_t wa_next_state(uint8_t state, char c) {\n')
        file.write(f'    return states_functions[state](c);\n')
        file.write('}\n\n')
    
    def generate_h(self, name):
        file = open(f'{name}.h', 'w')
        self.write_header(file)
        # Write constants header of the file
        file.write(f"#ifndef {name.upper()}_H_\n")
        file.write(f"#define {name.upper()}_H_\n")
        file.write('\n')
        file.write('#include <stdint.h>\n')
        file.write('#include <stdbool.h>\n')
        file.write('\n')

        # Generate state names
        constant_counter = 0
        for state in self.table:
            file.write(f"#define WA_{state.upper()} {constant_counter}\n")
            constant_counter += 1
        file.write('\n')

        # Generate token type
        constant_counter = 1
        for token_type in set(self.finals.values()):
            file.write(f"#define WA_{token_type.upper()} {constant_counter}\n")
            constant_counter += 1
        file.write('\n')

        # Write states functions prototype
        for state in self.table:
            file.write(f'uint8_t jump_{state}(char c);\n')
        file.write('\n');
        
        # Write next_state function prototype
        file.write(f'uint8_t wa_next_state(uint8_t state, char c);\n')
        # Write get_final function prototype
        file.write(f'uint8_t wa_get_final(uint8_t state);\n')

        # Write constant footer
        file.write('\n')
        file.write(f"#endif\n")
        file.close()

    def generate_c(self, name = 'wordautomaton'):
        self.generate_h(name)
        file = open(f'{name}.c', 'w')
        self.write_header(file)
        file.write(f'#include "{name}.h"\n')
        file.write('\n')

        self.generate_final_states_array(file)
        self.generate_states_functions_array(file)

        for state in self.table:
            self.generate_jump_function(state, file)
        
        self.generate_is_final_function(file)
        self.generate_next_state_function(file)

        file.close()

a = WordAutomaton()
a.update(keywords, 'keyword')
a.update(operators, 'operator')
a.generate_c()